from agent import *from models.products import *def run(context, session):    session.queue(Request("https://gear-vault.com/guitars/"), process_revlist, dict(cat='Guitars'))    session.queue(Request("https://gear-vault.com/amplifiers/"), process_revlist, dict(cat='Amplifiers'))def process_revlist(data, context, session):    for rev in data.xpath("//h3[@class='entry-title mh-posts-list-title']/a"):        url = rev.xpath("@href").string()        session.queue(Request(url), process_review, dict(context, url=url))    next = data.xpath("//a[@class='next page-numbers']//@href").string()    if next:        session.queue(Request(next), process_revlist, context)def process_review(data, context, session):    title = data.xpath("//title/text()").string()    if not 'Review' in title:        if 'Top' in title:            process_reviews(data, context, session)        return    product = Product()    product.name = title.split("Review")[0]    product.category = context['cat']    product.url = context['url']    product.ssid = context['url'].split("/")[-2]    review = Review()    review.type = 'pro'    review.title = title    review.url = product.url    review.ssid = product.ssid    review.date = data.xpath("//script[@class='rank-math-schema']/text()").string().split('"datePublished":')[1].split('"')[1].split('T')[0]    author = data.xpath("//a[@class='fn']").first()    if author:        author_name = author.xpath(".//text()").string()        author_url = author.xpath("@href").string()        review.authors.append(Person(name=author_name, profile_url=author_url, ssid=author_name))    conclusion = data.xpath("//div[@class='entry-content clearfix']//p[contains(., 'Conclusion:') ]/strong//text()").string(multiple=True)    if not conclusion:        conclusion = data.xpath('//p[contains(., "THE VERDICT")]//text()').string(multiple=True)    if not conclusion:        conclusion = data.xpath('//h2[contains(., "The Verdict")]/following-sibling::p[1]//text()').string(multiple=True)    if conclusion:        conclusion = conclusion.replace("Conclusion: ", "")        review.properties.append(ReviewProperty(type='conclusion', value=conclusion))    excerpt = data.xpath("//div[@class='entry-content clearfix']//p//text()").string(multiple=True)    if excerpt:        excerpt = excerpt.split("Conclusion:")[0]        if conclusion:            excerpt = excerpt.replace(conclusion, '').split('Originally published on')[0]        review.properties.append(ReviewProperty(type='excerpt', value=excerpt))    if conclusion or excerpt:        product.reviews.append(review)        session.emit(product)def process_reviews(data, context, session):    h1 = data.xpath("count(//div[@class='entry-content clearfix']/h1)")    title = data.xpath("//h1[@class='entry-title']/text()").string()    if not str(int(h1)) in title:        return    author = data.xpath("//a[@class='fn']").first()    if author:        author_name = author.xpath(".//text()").string()        author_url = author.xpath("@href").string()    for prod in data.xpath("//div[@class='entry-content clearfix']/h1"):        product = Product()        product.category = context['cat']        product.url = context['url']        product.name = prod.xpath(".//text()").string()        if '.' in product.name:            product.name = product.name.split('.')[1]        review = Review()        review.type = 'pro'        review.title = title        review.url = product.url        review.date = data.xpath("//script[@class='rank-math-schema']/text()").string().split('"datePublished":')[1].split('"')[1].split('T')[0]        if author:            review.authors.append(Person(name=author_name, profile_url=author_url, ssid=author_name))        excerpt = prod.xpath("following-sibling::p[1]//text()").string(multiple=True)        if excerpt:            review.properties.append(ReviewProperty(type='excerpt', value=excerpt))            review.ssid = review.digest() if author else review.digest(excerpt)            product.ssid = review.ssid            product.reviews.append(review)            session.emit(product)